import { execSync } from "child_process"; import fs from "fs";
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
const DEV="https://dev.avesa.lt";
const WPU=(process.env.WP_USER||"").trim();
const WPP=(process.env.WP_APP_PASS||"").replace(/\s+/g,"");
const MANIFEST=JSON.parse(Buffer.from("","base64").toString("utf8"));
function putFile(name,str){ try{ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'ml',branch:'main',content:Buffer.from(str,'utf8').toString('base64')}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/pf.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'}); }catch(e){} }
function api(path,method,obj){ let cmd='curl -sk -u "$WPU:$WPP" -H "Content-Type: application/json" '; if(method) cmd+='-X '+method+' '; if(obj){ fs.writeFileSync('/tmp/body.json', JSON.stringify(obj)); cmd+='-d @/tmp/body.json '; } cmd+='"'+DEV+path+'"'; try{ return execSync(cmd,{encoding:'utf8',maxBuffer:20000000,timeout:60000,env:{...process.env,WPU,WPP}}); }catch(e){ return 'EXC'; }}
function get(path){ try{ return execSync('curl -sk -u "$WPU:$WPP" --max-time 50 "'+DEV+path+'"',{encoding:'utf8',maxBuffer:20000000,timeout:55000,env:{...process.env,WPU,WPP}}); }catch(e){ return 'EXC'; } }
function code(u){ try{ return execSync('curl -sk -o /dev/null -w "%{http_code}" -u "$WPU:$WPP" "'+DEV+u+'"',{encoding:'utf8',timeout:30000,env:{...process.env,WPU,WPP}}).trim(); }catch(e){ return 'EXC'; } }
const out={pages:{}};
for (const [slug, info] of Object.entries(MANIFEST)) {
  const body = Buffer.from(info.body_b64, 'base64').toString('utf8');
  const exist=get('/wp-json/wp/v2/pages?slug='+slug+'&status=any&_fields=id');
  let existId=0; try{ const a=JSON.parse(exist); if(Array.isArray(a)&&a.length) existId=a[0].id; }catch(e){}
  let pageId=existId, action='';
  if(existId){ api('/wp-json/wp/v2/pages/'+existId,'POST',{title:info.title,content:body,status:'publish'}); action='updated'; }
  else { const c=api('/wp-json/wp/v2/pages','POST',{title:info.title,slug:slug,content:body,status:'publish'}); action='created'; try{ pageId=JSON.parse(c).id; }catch(e){} }
  // QA
  const httpc=code('/'+slug+'/');
  const html=get('/'+slug+'/?nc='+Date.now());
  const title=((html.match(/<title>([^<]*)<\/title>/i)||[])[1]||'').slice(0,50);
  const canonical=(html.match(/<link rel=["']canonical["'] href=["']([^"']*)["']/i)||['',''])[1].replace(DEV,'');
  const footer1_hidden=html.indexOf('.footer-widgets.footer.footer-1{display:none')>=0;
  out.pages[slug]={action,pageId,http:httpc,title,canonical,footer1_hidden};
}
putFile('mklegal.json',JSON.stringify(out));
console.log('done');
